+    ctx.assert_true(
+        approval.verify(&owner_key.verifying_key()).is_ok(),
+        "Enrollment approval should be valid",
+    );
+    ctx.assert_true(
+        !approval.is_expired(),
+        "Enrollment approval should not be expired",
+    );
+    ctx.assert_eq(
+        &approval.zone_id,
+        &ZoneId::owner(),
+        "Approval should be for z:owner",
+    );
+
+    ctx.finalize("pass");
