+    ctx.assert_true(
+        !outcome.resolved,
+        "ChooseByLease should fail for tied lease_seq",
+    );
+    ctx.assert_true(
+        outcome
+            .failure_reason
+            .as_ref()
+            .is_some_and(|r| r.contains("tie")),
