+    ctx.log_fork_resolution(&connector_id, "ManualResolution", &state_b_id, true);
+
+    connector.resume();
+    ctx.assert_eq(
+        &connector.state,
+        &ConnectorExecutionState::Resumed,
+        "Connector should be resumed",
+    );
+
+    ctx.finalize("pass");
+}
