+
+    ctx.log_phase(
+        "verify",
+        Some(json!({
+            "chain_type": "linear",
+            "fork_detected": false,
+            "head": state2_id.to_string(),
+            "seq": 2
+        })),
+    );
+
+    ctx.finalize("pass");
+}

