+        PostureAttributeValue::Number(300),
+    );
+    attributes.insert(
+        PostureAttributeKey::TpmPresent,
+        PostureAttributeValue::Bool(true),
+    );
+    attributes.insert(
+        PostureAttributeKey::SecureBootEnabled,
